import machine
import time
import network
from umqtt.simple import MQTTClient

# Wi-Fi configuration
WIFI_SSID = "YOUR_WIFI_SSID"
WIFI_PASSWORD = "YOUR_WIFI_PASSWORD"

# MQTT configuration
MQTT_BROKER = "YOUR_MQTT_BROKER_IP" # e.g., "192.168.1.100" or "broker.hivemq.com"
MQTT_CLIENT_ID = "esp32_sensor_01"
MQTT_TOPIC_TEMP = "sensors/temp"

# Sensor simulation (replace with actual sensor code)
def read_temperature():
    # Simulate reading a temperature sensor (e.g., from DHT11/DHT22 or DS18B20)
    # For demonstration, we'll return a dummy value
    return 25.0 + (time.time() % 100) / 50.0 # Returns a value between 25.0 and 27.0

def do_connect():
    sta_if = network.WLAN(network.STA_IF)
    if not sta_if.isconnected():
        print('connecting to network...')
        sta_if.active(True)
        sta_if.connect(WIFI_SSID, WIFI_PASSWORD)
        while not sta_if.isconnected():
            pass
    print('network config:', sta_if.ifconfig())

def main():
    do_connect()

    client = MQTTClient(MQTT_CLIENT_ID, MQTT_BROKER)

    try:
        client.connect()
        print("Connected to MQTT broker:", MQTT_BROKER)
    except OSError as e:
        print("Failed to connect to MQTT broker:", e)
        # Attempt to reconnect or reset if connection fails
        machine.reset()

    while True:
        try:
            temperature = read_temperature()
            msg = "{:.2f}".format(temperature)

            print(f"Publishing to '{MQTT_TOPIC_TEMP}': {msg}")
            client.publish(MQTT_TOPIC_TEMP, msg)

        except Exception as e:
            print(f"Error during publish: {e}")
            try:
                # Attempt to reconnect if an error occurs
                client.reconnect()
                print("Reconnected to MQTT broker.")
            except OSError as e_reconnect:
                print(f"Failed to reconnect: {e_reconnect}. Resetting...")
                machine.reset() # Reset the ESP32 if reconnection fails

        time.sleep(10) # Publish every 10 seconds

if __name__ == "__main__":
    main()